import { z } from 'zod';
import { taskStatusEnum } from '../db/schema.js';
import { taskIdSchema, moduleIdSchema } from './common.js';

// ── Status transition map ───────────────────────────────────────────────────

const validTransitions: Record<string, string[]> = {
	todo: ['in-progress', 'skipped'],
	'in-progress': ['blocked', 'review', 'todo'],
	blocked: ['in-progress', 'todo'],
	review: ['done', 'in-progress'],
	done: [],
	skipped: []
};

export function isValidTransition(from: string, to: string): boolean {
	return validTransitions[from]?.includes(to) ?? false;
}

// ── Claim ───────────────────────────────────────────────────────────────────

export const claimTaskSchema = z.object({
	assignee: z.string().min(1, 'Assignee is required').max(100)
});
export type ClaimTaskInput = z.infer<typeof claimTaskSchema>;

// ── Progress update ─────────────────────────────────────────────────────────

export const progressTaskSchema = z.object({
	progressMessage: z.string().max(5000).optional(),
	subTotal: z.number().int().nonnegative().optional(),
	subDone: z.number().int().nonnegative().optional()
}).refine(
	(data) => {
		if (data.subTotal !== undefined && data.subDone !== undefined) {
			return data.subDone <= data.subTotal;
		}
		return true;
	},
	{ message: 'sub_done cannot exceed sub_total', path: ['subDone'] }
);
export type ProgressTaskInput = z.infer<typeof progressTaskSchema>;

// ── Complete ────────────────────────────────────────────────────────────────

export const completeTaskSchema = z.object({
	commitHash: z.string().max(40).optional(),
	progressMessage: z.string().max(5000).optional()
});
export type CompleteTaskInput = z.infer<typeof completeTaskSchema>;

// ── Admin action ────────────────────────────────────────────────────────────

export const adminTaskActionSchema = z.object({
	status: z.enum(taskStatusEnum),
	progressMessage: z.string().max(5000).optional()
});
export type AdminTaskActionInput = z.infer<typeof adminTaskActionSchema>;

// ── Response (with resolved references) ─────────────────────────────────────

export const taskResponseSchema = z.object({
	id: taskIdSchema,
	shortId: z.number().int().positive(),
	moduleId: moduleIdSchema,
	title: z.string(),
	description: z.string().nullable(),
	references: z.string().nullable(),
	status: z.enum(taskStatusEnum),
	assignee: z.string().nullable(),
	subTotal: z.number().int().nonnegative(),
	subDone: z.number().int().nonnegative(),
	progressMessage: z.string().nullable(),
	commitHash: z.string().nullable(),
	createdAt: z.string().datetime(),
	updatedAt: z.string().datetime(),
	reportedAt: z.string().datetime().nullable()
});
export type TaskResponse = z.infer<typeof taskResponseSchema>;

import { eq, desc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { milestones, modules, tasks } from '$lib/db/schema.js';
import type { CreateMilestoneInput, UpdateMilestoneInput } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next MS-{seq} ID by querying max existing seq. */
export async function nextMilestoneId(db: BetterSQLite3Database<any>): Promise<string> {
	const rows = await db.select({ id: milestones.id }).from(milestones).all();
	let maxSeq = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('MS-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MS-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createMilestone(
	db: BetterSQLite3Database<any>,
	data: CreateMilestoneInput
) {
	const id = await nextMilestoneId(db);
	const result = await db
		.insert(milestones)
		.values({
			id,
			title: data.title,
			sourceMd: data.sourceMd ?? null,
			gitUrl: data.gitUrl && data.gitUrl !== '' ? data.gitUrl : null
		})
		.returning()
		.get();
	return formatMilestoneResponse(result);
}

// ── List ─────────────────────────────────────────────────────────────────────

export async function listMilestones(db: BetterSQLite3Database<any>) {
	const rows = await db.select().from(milestones).orderBy(desc(milestones.createdAt), desc(milestones.id)).all();
	return rows.map(formatMilestoneResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getMilestone(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!milestone) return null;

	// Fetch modules for this milestone
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, id))
		.all();

	// Fetch tasks for each module
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();
			return {
				...formatModuleResponse(mod),
				tasks: taskRows.map(formatTaskResponse)
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateMilestone(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateMilestoneInput
) {
	const existing = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.title !== undefined) updates.title = data.title;
	if (data.sourceMd !== undefined) updates.sourceMd = data.sourceMd ?? null;
	if (data.gitUrl !== undefined) updates.gitUrl = data.gitUrl === '' ? null : data.gitUrl;
	if (data.status !== undefined) updates.status = data.status;

	if (Object.keys(updates).length === 0) {
		return formatMilestoneResponse(existing);
	}

	const result = await db
		.update(milestones)
		.set(updates)
		.where(eq(milestones.id, id))
		.returning()
		.get();

	return formatMilestoneResponse(result);
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

export { formatModuleResponse, formatTaskResponse };

import { z } from 'zod';

// ── Pagination ──────────────────────────────────────────────────────────────

export const paginationQuerySchema = z.object({
	page: z.coerce.number().int().positive().default(1),
	perPage: z.coerce.number().int().positive().max(100).default(20)
});
export type PaginationQuery = z.infer<typeof paginationQuerySchema>;

export const paginatedResponseSchema = <T extends z.ZodTypeAny>(itemSchema: T) =>
	z.object({
		data: z.array(itemSchema),
		pagination: z.object({
			page: z.number().int().positive(),
			perPage: z.number().int().positive(),
			total: z.number().int().nonnegative(),
			totalPages: z.number().int().nonnegative()
		})
	});

// ── Error response ──────────────────────────────────────────────────────────

export const fieldErrorSchema = z.object({
	field: z.string(),
	message: z.string()
});
export type FieldError = z.infer<typeof fieldErrorSchema>;

export const errorResponseSchema = z.object({
	error: z.object({
		code: z.string(),
		message: z.string(),
		details: z.array(fieldErrorSchema).optional()
	})
});
export type ErrorResponse = z.infer<typeof errorResponseSchema>;

// ── ID formats ──────────────────────────────────────────────────────────────

export const milestoneIdSchema = z.string().regex(/^MS-\d+$/, 'Must match MS-{seq}');
export const moduleIdSchema = z.string().regex(/^MOD-\d+-\d+$/, 'Must match MOD-{ms_seq}-{seq}');
export const taskIdSchema = z.string().regex(/^TASK-\d+$/, 'Must match TASK-{seq}');

// ── Source markdown size limit (1 MB) ───────────────────────────────────────

export const SOURCE_MD_MAX_BYTES = 1_048_576;
export const sourceMdSchema = z
	.string()
	.max(SOURCE_MD_MAX_BYTES, `source_md must be under ${SOURCE_MD_MAX_BYTES} bytes`);

import { eq, asc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, milestones } from '$lib/db/schema.js';
import type { CreateModuleInput, UpdateModuleInput } from '$lib/schemas/index.js';

/** Body data for createModule (milestoneId comes from URL param). */
type CreateModuleBody = Omit<CreateModuleInput, 'milestoneId'>;

// ── ID Generation ────────────────────────────────────────────────────────────

/** Generate MOD-{milestone_seq}-{next_seq} ID. */
export async function nextModuleId(
	db: BetterSQLite3Database<any>,
	milestoneId: string
): Promise<string> {
	const msSeq = milestoneId.replace('MS-', '');
	const rows = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();
	let maxSeq = 0;
	for (const row of rows) {
		// Format: MOD-{msSeq}-{seq}
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MOD-${msSeq}-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createModule(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	data: CreateModuleBody
) {
	// Verify milestone exists
	const ms = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!ms) return null;

	const id = await nextModuleId(db, milestoneId);
	const result = await db
		.insert(modules)
		.values({
			id,
			milestoneId,
			name: data.name,
			description: data.description ?? null,
			sortOrder: data.sortOrder ?? 0
		})
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── List by Milestone ────────────────────────────────────────────────────────

export async function listModulesByMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string
) {
	const rows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();
	return rows.map(formatModuleResponse);
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateModule(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateModuleInput
) {
	const existing = await db.select().from(modules).where(eq(modules.id, id)).get();
	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.name !== undefined) updates.name = data.name;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.status !== undefined) updates.status = data.status;
	if (data.sortOrder !== undefined) updates.sortOrder = data.sortOrder;

	if (Object.keys(updates).length === 0) {
		return formatModuleResponse(existing);
	}

	const result = await db
		.update(modules)
		.set(updates)
		.where(eq(modules.id, id))
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

import { redirect, json } from '@sveltejs/kit';
import type { Handle } from '@sveltejs/kit';
import { checkAuth } from '$lib/server/auth.js';

export const handle: Handle = async ({ event, resolve }) => {
	const { url, request, cookies } = event;
	const path = url.pathname;

	// Skip auth for static assets and prerendered pages
	if (path.startsWith('/_app/') || path.startsWith('/favicon')) {
		return resolve(event);
	}

	// Public routes — no auth required
	const publicRoutes = ['/login', '/api/auth/login', '/api/auth/logout'];
	if (publicRoutes.some((r) => path === r || path.startsWith(r + '/'))) {
		// If already authenticated and visiting /login, redirect to home
		if (path === '/login') {
			const cookieHeader = request.headers.get('cookie');
			const authHeader = request.headers.get('authorization');
			const result = checkAuth(cookieHeader, authHeader);
			if (result.authenticated) {
				throw redirect(302, '/');
			}
		}
		return resolve(event);
	}

	// ── API routes: require auth (cookie or bearer) ──
	if (path.startsWith('/api/')) {
		const cookieHeader = request.headers.get('cookie');
		const authHeader = request.headers.get('authorization');
		const result = checkAuth(cookieHeader, authHeader);

		if (!result.authenticated) {
			// Return 401 JSON for API routes
			return json(
				{
					error: 'unauthorized',
					message: result.reason === 'invalid_bearer_token' ? '无效的 API Key' : '请先登录'
				},
				{ status: 401 }
			);
		}

		// Attach auth method to locals for downstream use
		event.locals.authMethod = result.method;
		return resolve(event);
	}

	// ── Page routes: require cookie auth, redirect to /login ──
	const cookieHeader = request.headers.get('cookie');
	const authHeader = request.headers.get('authorization');
	const result = checkAuth(cookieHeader, authHeader);

	if (!result.authenticated) {
		throw redirect(302, '/login');
	}

	event.locals.authMethod = result.method;
	return resolve(event);
};

import { json, error } from '@sveltejs/kit';
import type { PageServerLoad } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone } from '$lib/server/milestone-service.js';

export const load: PageServerLoad = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		throw error(404, `里程碑 ${params.id} 不存在`);
	}
	return { milestone };
};

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { db } from '$lib/db/index.js';
import { getMilestone, updateMilestone } from '$lib/server/milestone-service.js';
import { updateMilestoneSchema } from '$lib/schemas/index.js';

export const GET: RequestHandler = async ({ params }) => {
	const milestone = await getMilestone(db, params.id);
	if (!milestone) {
		return json({ error: 'not_found', message: `Milestone ${params.id} not found` }, { status: 404 });
	}
	return json(milestone);
};

export const PATCH: RequestHandler = async ({ params, request }) => {
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = updateMilestoneSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	const milestone = await updateMilestone(db, params.id, parsed.data);
	if (!milestone) {
		return json({ error: 'not_found', message: `Milestone ${params.id} not found` }, { status: 404 });
	}
	return json(milestone);
};

import { eq, asc, sql, and, inArray } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { tasks, modules, milestones } from '$lib/db/schema.js';
import type { TaskStatus } from '$lib/db/schema.js';
import type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput
} from '$lib/schemas/index.js';
import { isValidTransition } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next TASK-{global_seq} ID and short_id. */
export async function nextTaskId(db: BetterSQLite3Database<any>): Promise<{ id: string; shortId: number }> {
	const rows = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxSeq = 0;
	let maxShort = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
		if (row.shortId > maxShort) maxShort = row.shortId;
	}
	return { id: `TASK-${maxSeq + 1}`, shortId: maxShort + 1 };
}

// ── List (with filters) ─────────────────────────────────────────────────────

export interface TaskFilters {
	status?: string;
	milestoneId?: string;
	moduleId?: string;
}

export async function listTasks(
	db: BetterSQLite3Database<any>,
	filters: TaskFilters = {}
) {
	const conditions = [];
	if (filters.status) conditions.push(eq(tasks.status, filters.status as TaskStatus));
	if (filters.moduleId) conditions.push(eq(tasks.moduleId, filters.moduleId));

	// If milestoneId, join through modules
	if (filters.milestoneId) {
		const modRows = await db
			.select({ id: modules.id })
			.from(modules)
			.where(eq(modules.milestoneId, filters.milestoneId))
			.all();
		const modIds = modRows.map((m) => m.id);
		if (modIds.length === 0) return [];
		conditions.push(inArray(tasks.moduleId, modIds));
	}

	const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
	const rows = await db
		.select()
		.from(tasks)
		.where(whereClause)
		.orderBy(asc(tasks.shortId))
		.all();
	return rows.map(formatTaskResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getTask(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const row = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!row) return null;

	// Resolve module and milestone info
	const mod = await db.select().from(modules).where(eq(modules.id, row.moduleId)).get();
	const milestone = mod
		? await db.select().from(milestones).where(eq(milestones.id, mod.milestoneId)).get()
		: null;

	return {
		...formatTaskResponse(row),
		module: mod
			? {
					id: mod.id,
					milestoneId: mod.milestoneId,
					name: mod.name,
					status: mod.status
				}
			: null,
		milestone: milestone
			? {
					id: milestone.id,
					title: milestone.title,
					status: milestone.status
				}
			: null
	};
}

// ── Claim (optimistic lock) ──────────────────────────────────────────────────

export async function claimTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ClaimTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Only allow claiming if task is todo or in-progress
	if (existing.status !== 'todo' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	// Optimistic lock: if already assigned to someone else, reject
	if (existing.assignee && existing.assignee !== data.assignee) {
		return {
			error: 'conflict' as const,
			currentAssignee: existing.assignee,
			task: formatTaskResponse(existing)
		};
	}

	// Transition status if needed
	const statusUpdate =
		existing.status === 'todo' ? 'in-progress' : undefined;

	const updates: Record<string, any> = { assignee: data.assignee };
	if (statusUpdate) updates.status = statusUpdate;
	updates.updatedAt = sql`(unixepoch())`;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Progress ─────────────────────────────────────────────────────────────────

export async function progressTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ProgressTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'in-progress' && existing.status !== 'todo' && existing.status !== 'blocked') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;
	if (data.subTotal !== undefined) updates.subTotal = data.subTotal;
	if (data.subDone !== undefined) updates.subDone = data.subDone;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Complete ─────────────────────────────────────────────────────────────────

export async function completeTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: CompleteTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Must be in review or in-progress to complete
	if (existing.status !== 'review' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'done',
		updatedAt: sql`(unixepoch())`,
		reportedAt: sql`(unixepoch())`
	};
	if (data.commitHash !== undefined) updates.commitHash = data.commitHash ?? null;
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Admin Action ─────────────────────────────────────────────────────────────

export type AdminActionError = {
	error: 'not_found' | 'invalid_transition' | 'invalid_status';
	detail?: string;
};

export async function adminTaskAction(
	db: BetterSQLite3Database<any>,
	id: string,
	data: AdminTaskActionInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Admin can force any status, but validate transition for non-force actions
	// For admin actions, we allow any status change (admin override)
	const updates: Record<string, any> = {
		status: data.status,
		updatedAt: sql`(unixepoch())`
	};

	// If setting to done, also set reportedAt
	if (data.status === 'done' && !existing.reportedAt) {
		updates.reportedAt = sql`(unixepoch())`;
	}
	// If reopening from done, clear reportedAt
	if (data.status !== 'done' && existing.reportedAt) {
		updates.reportedAt = null;
	}

	if (data.progressMessage !== undefined) {
		updates.progressMessage = data.progressMessage ?? null;
	}

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

import Database from 'better-sqlite3';
import { drizzle } from 'drizzle-orm/better-sqlite3';
import path from 'node:path';
import fs from 'node:fs';

const dbPath = process.env.DATABASE_PATH || path.join(process.cwd(), 'data', 'tracker.db');

// Ensure data directory exists
const dir = path.dirname(dbPath);
if (!fs.existsSync(dir)) {
	fs.mkdirSync(dir, { recursive: true });
}

const sqlite = new Database(dbPath);

// Enable WAL mode for concurrent read/write support
sqlite.pragma('journal_mode = WAL');
// Enable foreign key enforcement
sqlite.pragma('foreign_keys = ON');

export const db = drizzle(sqlite);
export default db;

import { createHmac, randomBytes, timingSafeEqual } from 'node:crypto';

// ── Configuration ───────────────────────────────────────────────────────────

function getEnvOrThrow(key: string): string {
	const val = process.env[key];
	if (!val) throw new Error(`Missing required env var: ${key}`);
	return val;
}

/** Derive a signing secret from ADMIN_PASSWORD (always available in production). */
function getSigningSecret(): string {
	const pw = process.env.ADMIN_PASSWORD || '';
	// Use HMAC of a fixed salt with the password as key to derive a stable secret
	return createHmac('sha256', pw).update('milestone-tracker-session-salt').digest('hex');
}

/** Parse comma-separated API_KEYS from .env */
function getApiKeys(): string[] {
	const raw = process.env.API_KEYS || '';
	return raw
		.split(',')
		.map((k) => k.trim())
		.filter(Boolean);
}

// ── Session Management (stateless signed tokens) ────────────────────────────
// Token format: `{randomHex}.{hmac-sha256-hex}`
// This is stateless — no server-side session store needed.

const SESSION_COOKIE_NAME = 'mt_session';
const SESSION_MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

export interface Session {
	token: string;
	signedToken: string;
	createdAt: number;
	maxAge: number;
}

/** Create a new signed session token. */
export function createSession(): Session {
	const token = randomBytes(32).toString('hex');
	const signature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');
	const signedToken = `${token}.${signature}`;
	return {
		token,
		signedToken,
		createdAt: Date.now(),
		maxAge: SESSION_MAX_AGE_MS
	};
}

/** Verify a signed session token. Returns true if valid and not expired. */
export function verifySession(signedToken: string, maxAge: number = SESSION_MAX_AGE_MS): boolean {
	const lastDot = signedToken.lastIndexOf('.');
	if (lastDot === -1) return false;

	const token = signedToken.substring(0, lastDot);
	const providedSignature = signedToken.substring(lastDot + 1);

	if (!token || !providedSignature) return false;

	const expectedSignature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');

	try {
		return timingSafeEqual(
			Buffer.from(providedSignature, 'hex'),
			Buffer.from(expectedSignature, 'hex')
		);
	} catch {
		return false;
	}
}

/** Destroy a session by returning a cookie that immediately expires. */
export function destroySessionCookie(): { name: string; value: string; options: SessionCookieOptions } {
	return {
		name: SESSION_COOKIE_NAME,
		value: '',
		options: {
			path: '/',
			httpOnly: true,
			secure: process.env.NODE_ENV === 'production',
			sameSite: 'lax',
			maxAge: 0
		}
	};
}

/** Build a Set-Cookie header value for a new session. */
export function buildSessionCookie(session: Session): string {
	const opts = sessionCookieOptions(session.maxAge);
	return `${SESSION_COOKIE_NAME}=${session.signedToken}; Path=${opts.path}; HttpOnly${opts.secure ? '; Secure' : ''}; SameSite=${opts.sameSite}; Max-Age=${Math.floor(opts.maxAge / 1000)}`;
}

// ── Bearer Token Validation ─────────────────────────────────────────────────

/** Validate a Bearer token against API_KEYS from .env. */
export function validateBearerToken(token: string): boolean {
	const apiKeys = getApiKeys();
	const tokenBuf = Buffer.from(token);
	return apiKeys.some((key) => {
		const keyBuf = Buffer.from(key);
		if (tokenBuf.length !== keyBuf.length) return false;
		return timingSafeEqual(tokenBuf, keyBuf);
	});
}

// ── Cookie Helpers ──────────────────────────────────────────────────────────

export interface SessionCookieOptions {
	path: string;
	httpOnly: boolean;
	secure: boolean;
	sameSite: 'lax' | 'strict';
	maxAge: number; // seconds
}

function sessionCookieOptions(maxAgeMs: number): SessionCookieOptions {
	return {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(maxAgeMs / 1000)
	};
}

// ── Auth Middleware Logic ────────────────────────────────────────────────────
// Extracted as pure functions for testability. Used by hooks.server.ts.

export type AuthResult =
	| { authenticated: true; method: 'cookie' | 'bearer' }
	| { authenticated: false; reason: string };

/** Extract the signed session token from a Cookie header string. */
export function extractSessionCookie(cookieHeader: string | null): string | null {
	if (!cookieHeader) return null;
	const match = cookieHeader.match(/(?:^|;\s*)mt_session=([^;]+)/);
	return match ? match[1] : null;
}

/** Extract Bearer token from Authorization header. */
export function extractBearerToken(authHeader: string | null): string | null {
	if (!authHeader) return null;
	const parts = authHeader.split(' ');
	if (parts.length !== 2 || parts[0] !== 'Bearer') return null;
	return parts[1] || null;
}

/**
 * Check authentication from cookie and/or authorization headers.
 * Returns the auth result without performing any side effects.
 */
export function checkAuth(
	cookieHeader: string | null,
	authHeader: string | null
): AuthResult {
	// 1. Try Bearer token first (CLI/API usage)
	const bearer = extractBearerToken(authHeader);
	if (bearer) {
		if (validateBearerToken(bearer)) {
			return { authenticated: true, method: 'bearer' };
		}
		return { authenticated: false, reason: 'invalid_bearer_token' };
	}

	// 2. Try session cookie (Web usage)
	const sessionToken = extractSessionCookie(cookieHeader);
	if (sessionToken) {
		if (verifySession(sessionToken)) {
			return { authenticated: true, method: 'cookie' };
		}
		return { authenticated: false, reason: 'invalid_session' };
	}

	return { authenticated: false, reason: 'no_credentials' };
}

/** Validate a login password against ADMIN_PASSWORD env var. */
export function validatePassword(password: string): boolean {
	const adminPassword = process.env.ADMIN_PASSWORD;
	if (!adminPassword) return false;
	const pwBuf = Buffer.from(password);
	const adminBuf = Buffer.from(adminPassword);
	if (pwBuf.length !== adminBuf.length) return false;
	return timingSafeEqual(pwBuf, adminBuf);
}

